// Categorias de Leroy Merlin para construccion
// Edita esta lista para añadir/quitar categorias
const categories = [
  { slug: 'azulejos-y-baldosas', name: 'Azulejos y baldosas' },
  { slug: 'cemento-y-mortero', name: 'Cemento y mortero' },
  { slug: 'ladrillos-y-bloques', name: 'Ladrillos y bloques' },
  { slug: 'yeso-y-escayola', name: 'Yeso y escayola' },
  { slug: 'impermeabilizacion', name: 'Impermeabilizacion' },
  { slug: 'aislamiento', name: 'Aislamiento' },
  { slug: 'tubos-y-accesorios', name: 'Tubos y accesorios' },
  { slug: 'griferia', name: 'Griferia' },
  { slug: 'sanitarios', name: 'Sanitarios' },
  { slug: 'pintura-interior', name: 'Pintura interior' },
  { slug: 'pintura-exterior', name: 'Pintura exterior' },
  { slug: 'herramientas-manuales', name: 'Herramientas manuales' },
  { slug: 'herramientas-electricas', name: 'Herramientas electricas' },
  { slug: 'madera-y-tableros', name: 'Madera y tableros' },
  { slug: 'tornilleria-y-fijaciones', name: 'Tornilleria y fijaciones' }
];

return categories.map(c => ({ json: c }));

// Extrae productos del HTML de Leroy Merlin
// El HTML puede cambiar — ajusta los selectores si es necesario
const html = $input.first().json.data || $input.first().json.body || '';
const category = $input.first().json.slug || 'general';

const products = [];

// Patron 1: JSON-LD structured data
const jsonLdMatches = html.match(/<script type="application\/ld\+json">[\s\S]*?<\/script>/g) || [];
for (const match of jsonLdMatches) {
  try {
    const jsonStr = match.replace(/<script[^>]*>/, '').replace(/<\/script>/, '').trim();
    const data = JSON.parse(jsonStr);
    if (data['@type'] === 'Product' || (data['@type'] === 'ItemList' && data.itemListElement)) {
      const items = data.itemListElement || [data];
      for (const item of items) {
        const product = item.item || item;
        if (product.name && product.offers) {
          const offer = Array.isArray(product.offers) ? product.offers[0] : product.offers;
          products.push({
            name: product.name,
            sku: product.sku || product.productID || '',
            brand: product.brand?.name || '',
            price: parseFloat(offer.price) || 0,
            unit: 'ud',
            url: product.url || '',
            category: category,
            is_available: offer.availability?.includes('InStock') ?? true
          });
        }
      }
    }
  } catch(e) { /* skip malformed JSON-LD */ }
}

// Patron 2: data attributes en product cards
const cardPattern = /data-product-id="([^"]+)"[\s\S]*?data-product-name="([^"]+)"[\s\S]*?data-product-price="([^"]+)"/g;
let match;
while ((match = cardPattern.exec(html)) !== null) {
  const existing = products.find(p => p.sku === match[1]);
  if (!existing) {
    products.push({
      name: match[2],
      sku: match[1],
      price: parseFloat(match[3]) || 0,
      unit: 'ud',
      category: category,
      is_available: true
    });
  }
}

// Patron 3: regex fallback para precios en el HTML
if (products.length === 0) {
  const pricePattern = /class="[^"]*product[^"]*"[\s\S]*?<[^>]*class="[^"]*name[^"]*"[^>]*>([^<]+)<[\s\S]*?(\d+[.,]\d{2})\s*&euro;/g;
  while ((match = pricePattern.exec(html)) !== null) {
    products.push({
      name: match[1].trim(),
      price: parseFloat(match[2].replace(',', '.')) || 0,
      unit: 'ud',
      category: category,
      is_available: true
    });
  }
}

if (products.length === 0) {
  return [{ json: { _empty: true, category, message: 'No se encontraron productos. Revisa los selectores.' } }];
}

return products.map(p => ({ json: p }));

// Agrupa items en formato webhook ENLAZE
const items = $input.all().map(i => i.json);

return [{
  json: {
    action: 'upsert_products',
    source: {
      name: 'n8n-leroy-merlin-scraper',
      type: 'n8n_webhook',
      url: 'https://www.leroymerlin.es'
    },
    provider: {
      name: 'Leroy Merlin',
      website: 'https://www.leroymerlin.es',
      region: 'ES'
    },
    items: items,
    metadata: {
      scraped_at: new Date().toISOString(),
      workflow_id: 'leroy-merlin-scraper',
      n8n_execution_id: $execution.id
    }
  }
}];

// Log resultado
const response = $input.first().json;
console.log(`ENLAZE webhook response: created=${response.created}, updated=${response.updated}, errors=${response.errors?.length || 0}`);
return $input.all();
